(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"wheel-rpm",fields:[{"key":"speedKmh","label":"주행속도 (km/h)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"tireDiameterMm","label":"타이어 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.speedKmh),d=Number(x.tireDiameterMm);if(![s,d].every(Number.isFinite)||s<0||d<=0)return{error:"속도는 0 이상, 타이어 외경은 0보다 크게 입력해 주세요."};var circumference=Math.PI*d/1000,rpm=s*1000/60/circumference;return{rpm:rpm,circumferenceM:circumference,revolutionsPerKm:1000/circumference};},format:function(r,api){return api.resultCard("바퀴 회전수",api.formatNumber(r.rpm,2)+" RPM","")+api.resultCard("1km당 회전수",api.formatNumber(r.revolutionsPerKm,2)+"회","둘레 "+api.formatNumber(r.circumferenceM,3)+"m");}},{id:"speedometer-error",fields:[{"key":"oldDiameterMm","label":"기존 타이어 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newDiameterMm","label":"새 타이어 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"indicatedSpeed","label":"속도계 표시속도 (km/h)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"공기압·하중·마모 상태에 따라 실제 오차가 달라질 수 있습니다.",compute:function(x){var o=Number(x.oldDiameterMm),n=Number(x.newDiameterMm),s=Number(x.indicatedSpeed);if(![o,n,s].every(Number.isFinite)||o<=0||n<=0||s<0)return{error:"두 외경은 0보다 크게, 표시속도는 0 이상으로 입력해 주세요."};var ratio=n/o,actual=s*ratio;return{ratio:ratio,actualSpeed:actual,errorKmh:actual-s,errorPercent:(ratio-1)*100};},format:function(r,api){return api.resultCard("예상 실제속도",api.formatNumber(r.actualSpeed,2)+"km/h","")+api.resultCard("표시속도와 차이",api.formatNumber(r.errorKmh,2)+"km/h",api.formatNumber(r.errorPercent,2)+"%");}},{id:"odometer-correction",fields:[{"key":"oldDiameterMm","label":"기존 타이어 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"newDiameterMm","label":"새 타이어 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"indicatedDistanceKm","label":"계기판 주행거리 (km)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var o=Number(x.oldDiameterMm),n=Number(x.newDiameterMm),d=Number(x.indicatedDistanceKm);if(![o,n,d].every(Number.isFinite)||o<=0||n<=0||d<0)return{error:"두 외경은 0보다 크게, 주행거리는 0 이상으로 입력해 주세요."};var actual=d*n/o;return{actualDistanceKm:actual,differenceKm:actual-d,correctionPercent:(n/o-1)*100};},format:function(r,api){return api.resultCard("보정 실제거리",api.formatNumber(r.actualDistanceKm,3)+"km","")+api.resultCard("거리 차이",api.formatNumber(r.differenceKm,3)+"km",api.formatNumber(r.correctionPercent,2)+"%");}},{id:"braking-distance-estimate",fields:[{"key":"speedKmh","label":"주행속도 (km/h)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"reactionSeconds","label":"반응시간 (초)","type":"number","placeholder":"","default":"1","options":[],"raw":false},{"key":"deceleration","label":"감속도 (m/s²)","type":"number","placeholder":"","default":"7","options":[],"raw":false}],hint:"노면·타이어·차량 상태를 단순화한 추정값이며 실제 안전거리 기준을 대체하지 않습니다.",compute:function(x){var k=Number(x.speedKmh),t=Number(x.reactionSeconds),a=Number(x.deceleration);if(![k,t,a].every(Number.isFinite)||k<0||t<0||a<=0)return{error:"속도와 반응시간은 0 이상, 감속도는 0보다 크게 입력해 주세요."};var v=k/3.6,react=v*t,brake=v*v/(2*a);return{reactionDistanceM:react,brakingDistanceM:brake,totalDistanceM:react+brake};},format:function(r,api){return api.resultCard("총 정지거리 추정",api.formatNumber(r.totalDistanceM,2)+"m","")+api.resultCard("반응거리 · 제동거리",api.formatNumber(r.reactionDistanceM,2)+"m · "+api.formatNumber(r.brakingDistanceM,2)+"m","");}},{id:"fuel-stop-count",fields:[{"key":"distanceKm","label":"총 주행거리 (km)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"efficiencyKmpl","label":"연비 (km/L)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"tankLiters","label":"연료탱크 용량 (L)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"startingLiters","label":"출발 시 연료 (L)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"예비연료와 실제 주유소 위치는 별도로 고려하세요.",compute:function(x){var d=Number(x.distanceKm),e=Number(x.efficiencyKmpl),t=Number(x.tankLiters),s=Number(x.startingLiters);if(![d,e,t,s].every(Number.isFinite)||d<0||e<=0||t<=0||s<0||s>t)return{error:"거리와 출발연료는 0 이상, 연비와 탱크용량은 0보다 크게, 출발연료는 탱크 이하로 입력해 주세요."};var need=d/e,extra=Math.max(0,need-s),stops=Math.ceil(extra/t-1e-12);return{fuelNeededL:need,additionalFuelL:extra,minimumStops:stops};},format:function(r,api){return api.resultCard("총 필요 연료",api.formatNumber(r.fuelNeededL,2)+"L","")+api.resultCard("추가 주유량",api.formatNumber(r.additionalFuelL,2)+"L","최소 "+api.formatNumber(r.minimumStops,0)+"회");}},{id:"payload-utilization",fields:[{"key":"maxPayloadKg","label":"최대 적재중량 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"actualPayloadKg","label":"실제 적재중량 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"차량 등록증의 허용 적재중량과 관련 법규를 우선 확인하세요.",compute:function(x){var m=Number(x.maxPayloadKg),a=Number(x.actualPayloadKg);if(![m,a].every(Number.isFinite)||m<=0||a<0)return{error:"최대 적재중량은 0보다 크게, 실제 적재중량은 0 이상으로 입력해 주세요."};return{utilizationPercent:a/m*100,remainingKg:m-a,overloadKg:Math.max(0,a-m)};},format:function(r,api){return api.resultCard("적재율",api.formatNumber(r.utilizationPercent,2)+"%","")+api.resultCard("남은 적재 여유",api.formatNumber(r.remainingKg,1)+"kg","초과 "+api.formatNumber(r.overloadKg,1)+"kg");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
